import{d as e}from"./app.2e1eaa90.js";const r={},a=e('<h1 id="订阅-rss-rss" tabindex="-1"><a class="header-anchor" href="#订阅-rss-rss" aria-hidden="true">#</a> 订阅 RSS (RSS)</h1><div class="custom-container warning"><p class="custom-container-title">WARNING</p><p>要使用本插件，你需要安装数据库支持。</p></div><p>koishi-plugin-rss 可用于订阅 RSS 信息源。</p><h2 id="指令-rss" tabindex="-1"><a class="header-anchor" href="#指令-rss" aria-hidden="true">#</a> 指令：rss</h2><p>订阅或取消订阅 RSS。</p><ul><li>基本语法：<code>rss &lt;url&gt;</code></li><li>选项列表： <ul><li><code>-l, --list</code> 查看订阅列表</li><li><code>-r, --remove</code> 取消订阅</li></ul></li></ul><h2 id="配置项" tabindex="-1"><a class="header-anchor" href="#配置项" aria-hidden="true">#</a> 配置项</h2><h3 id="timeout" tabindex="-1"><a class="header-anchor" href="#timeout" aria-hidden="true">#</a> timeout</h3><ul><li>类型: <code>number</code></li><li>默认值: <code>10000</code></li></ul><p>连接等待时间，单位为毫秒。</p><h3 id="refresh" tabindex="-1"><a class="header-anchor" href="#refresh" aria-hidden="true">#</a> refresh</h3><ul><li>类型: <code>number</code></li><li>默认值: <code>60000</code></li></ul><p>内容刷新的时间间隔，单位为毫秒。</p><h3 id="useragent" tabindex="-1"><a class="header-anchor" href="#useragent" aria-hidden="true">#</a> userAgent</h3><ul><li>类型: <code>string</code></li></ul><p>连接 RSS 源所用的 User Agent。</p>',16);r.render=function(e,r){return a};export default r;
